236	var measurementPattern = regexp.MustCompile(`(?i)(-?\d+(?:\.\d+)?)(?:\s*)(ms|s|sec|seconds?)?`)
237	
238	func normalizeMeasurement(stdout string) (float64, string) {
239		trimmed := strings.TrimSpace(stdout)
240		if trimmed == "" {
241			return 0, ""
242		}
243		if value, unit, ok := parseJSONMeasurement(trimmed); ok {
244			return value, unit
245		}
246		if value, unit, ok := parseTextMeasurement(trimmed); ok {
247			return value, unit
248		}
249		return 0, ""
250	}
251	
252	func parseJSONMeasurement(text string) (float64, string, bool) {
253		var obj map[string]any
254		if err := json.Unmarshal([]byte(text), &obj); err != nil {
255			return 0, "", false
256		}
257		if raw, ok := obj["value"]; ok {
258			switch v := raw.(type) {
259			case float64:
260				unit, _ := obj["unit"].(string)
261				return v, unit, true
262			case string:
263				if parsed, err := strconv.ParseFloat(v, 64); err == nil {
264					unit, _ := obj["unit"].(string)
265					return parsed, unit, true
266				}
267			}
268		}
269		return 0, "", false
270	}
271	
272	func parseTextMeasurement(text string) (float64, string, bool) {
273		match := measurementPattern.FindStringSubmatch(text)
274		if len(match) < 2 {
275			return 0, "", false
276		}
277		value, err := strconv.ParseFloat(match[1], 64)
278		if err != nil {
279			return 0, "", false
280		}
281		unit := ""
282		if len(match) >= 3 {
283			unit = strings.ToLower(match[2])
284		}
285		return value, unit, true
286	}
